  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="z" computer="DESKTOP-LC5V468" date="2025.05.11 15'56'30" map_xs="128" map_ys="128" north_angle="0" extra_map_edge="1" tileset="steppe" environment="Steppe_Final" players="8" name="Звероземье" id="new_beastlands" style="0" description="Хоть и крагарские звери давно покинули эту встревоженную войной землю, основные ее жители: берсерки, варвары и их слуги все еще населяют свой край, богатый на тимониевые залежи. Забрать у них территорию будет совсем не просто, но лидер, который окажется способен это сделать, получит огромное преимущество. &#xA; {— От Матвея Icpompeo Аль-Бороди.}" enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="0" elimination="1" allies="2" living_world_bird="0" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="1" generate_script="0" num_villages="0" num_special="0" num_villages_override="16-20" num_special_override="30-34">
